foreach ($closure->params as $i => $parameter) {
	if (!$parameter->var instanceof Variable || !is_string($parameter->var->name)) {
		throw new ShouldNotHappenException();
	}
	$paramExprString = sprintf('$%s', $parameter->var->name);
	$isNullable = $this->isParameterValueNullable($parameter);
	$nativeParameterType = $parameterType = $this->getFunctionType($parameter->type, $isNullable, $parameter->variadic);
	if ($callableParameters !== null) {
		$parameterType = self::intersectButNotNever($parameterType, $this->getCallableParameterType($parameter, $callableParameters, $i));
	}
	if ($nativeCallableParameters !== null) {
		$nativeParameterType = self::intersectButNotNever($nativeParameterType, $this->getCallableParameterType($parameter, $nativeCallableParameters, $i));
	}
	$expressionTypes[$paramExprString] = ExpressionTypeHolder::createYes($parameter->var, $parameterType);
	$nativeTypes[$paramExprString] = ExpressionTypeHolder::createYes($parameter->var, $nativeParameterType);
}

if (count($stmt->cond) > 0) {
	$storage = $originalStorage->duplicate();

	foreach ($stmt->cond as $condExpr) {
		$condResult = $this->processExprNode($stmt, $condExpr, $bodyScope, $storage, new NoopNodeCallback(), ExpressionContext::createDeep());
		$initScope = $condResult->getScope();
		$condResultScope = $condResult->getScope();

		// only the last condition expression is relevant whether the loop continues
		// see https://www.php.net/manual/en/control-structures.for.php
		if ($condExpr === $lastCondExpr) {
			$condTruthiness = ($this->treatPhpDocTypesAsCertain ? $condResultScope->getType($condExpr) : $condResultScope->getNativeType($condExpr))->toBoolean();
			$isIterableAtLeastOnce = $isIterableAtLeastOnce->and($condTruthiness->isTrue());
		}

		$hasYield = $hasYield || $condResult->hasYield();
		$throwPoints = array_merge($throwPoints, $condResult->getThrowPoints());
		$impurePoints = array_merge($impurePoints, $condResult->getImpurePoints());
		$bodyScope = $condResult->getTruthyScope();
	}
}

if ($classReflection->hasConstructor()) {
	$methodReflection = $classReflection->getConstructor();
	$asserts = $methodReflection->getAsserts();

	if ($asserts->getAll() !== []) {
		$parametersAcceptor = ParametersAcceptorSelector::selectFromArgs($scope, $expr->getArgs(), $methodReflection->getVariants(), $methodReflection->getNamedArgumentsVariants());

		$asserts = $asserts->mapTypes(static fn (Type $type) => TemplateTypeHelper::resolveTemplateTypes(
			$type,
			$parametersAcceptor->getResolvedTemplateTypeMap(),
			$parametersAcceptor instanceof ExtendedParametersAcceptor ? $parametersAcceptor->getCallSiteVarianceMap() : TemplateTypeVarianceMap::createEmpty(),
			TemplateTypeVariance::createInvariant(),
		));

		$specifiedTypes = $this->specifyTypesFromAsserts($context, $expr, $asserts, $parametersAcceptor, $scope);

		if ($specifiedTypes !== null) {
			return $specifiedTypes;
		}
	}
}

if ($prototype->isPublic()) {
	if (!$constantReflection->isPublic()) {
		$errors[] = RuleErrorBuilder::message(sprintf(
			'%s constant %s::%s overriding public constant %s::%s should also be public.',
			$constantReflection->isPrivate() ? 'Private' : 'Protected',
			$constantReflection->getDeclaringClass()->getDisplayName(false),
			$constantReflection->getName(),
			$prototype->getDeclaringClass()->getDisplayName(false),
			$prototype->getName(),
		))->identifier('classConstant.visibility')->nonIgnorable()->build();
	}
} elseif ($constantReflection->isPrivate()) {
	$errors[] = RuleErrorBuilder::message(sprintf(
		'Private constant %s::%s overriding protected constant %s::%s should be protected or public.',
		$constantReflection->getDeclaringClass()->getDisplayName(false),
		$constantReflection->getName(),
		$prototype->getDeclaringClass()->getDisplayName(false),
		$prototype->getName(),
	))->identifier('classConstant.visibility')->nonIgnorable()->build();
}

if ($parentThrowType->isVoid()->yes()) {
	if ($explicitParentThrowsVoid) {
		$errors[] = RuleErrorBuilder::message(sprintf(
			'Method %s::%s() should not throw %s because parent method %s::%s() has PHPDoc tag @throws void.',
			$method->getDeclaringClass()->getDisplayName(),
			$method->getName(),
			$throwType->describe(VerbosityLevel::typeOnly()),
			$parentMethodDeclaringClass->getDisplayName(),
			$parentMethod->getName(),
		))->identifier('throws.shouldBeVoid')->build();
	} else {
		$errors[] = RuleErrorBuilder::message(sprintf(
			'Method %s::%s() should not throw %s because parent method %s::%s() does not have PHPDoc tag @throws.',
			$method->getDeclaringClass()->getDisplayName(),
			$method->getName(),
			$throwType->describe(VerbosityLevel::typeOnly()),
			$parentMethodDeclaringClass->getDisplayName(),
			$parentMethod->getName(),
		))->identifier('throws.notCovariantWithImplicitVoid')->build();
	}
	continue;
}

if (
	!$parameter->passedByReference()->createsNewVariable()
	|| (!$isBuiltin && !$argumentValueType instanceof ErrorType)
) {
	// @see https://github.com/php/php-src/issues/21568#issuecomment-4148832540
	$isStrictTypes = $scope->isDeclareStrictTypes()
		&& (!$isBuiltin || !$parameterType->isCallable()->yes());
	$accepts = $this->ruleLevelHelper->accepts($parameterType, $argumentValueType, $isStrictTypes);

	if (!$accepts->result) {
		$verbosityLevel = VerbosityLevel::getRecommendedLevelByType($parameterType, $argumentValueType);
		$errors[] = RuleErrorBuilder::message(sprintf(
			$wrongArgumentTypeMessage,
			$this->describeParameter($parameter, $argumentName ?? $i + 1),
			$parameterType->describe($verbosityLevel),
			$argumentValueType->describe($verbosityLevel),
		))
			->identifier('argument.type')
			->line($argumentLine)
			->acceptsReasonsTip($accepts->reasons)
			->build();
	}
}

foreach ($parameterResults as $parameterIndex => [$parameterResult, $parameterType, $parentParameterType]) {
	if ($parameterResult->yes()) {
		continue;
	}
	if (!$parameterResult->no() && !$this->reportMaybes) {
		continue;
	}
	$parameter = $methodParameters[$parameterIndex];
	$parentParameter = $parentVariantParameters[$parameterIndex];
	$errors[] = RuleErrorBuilder::message(sprintf(
		'Parameter #%d $%s (%s) of method %s::%s() should be %s with parameter $%s (%s) of method %s::%s()',
		$parameterIndex + 1,
		$parameter->getName(),
		$parameterType->describe(VerbosityLevel::value()),
		$method->getDeclaringClass()->getDisplayName(),
		$method->getName(),
		$parameterResult->no() ? 'compatible' : 'contravariant',
		$parentParameter->getName(),
		$parentParameterType->describe(VerbosityLevel::value()),
		$parentMethodDeclaringClass->getDisplayName(),
		$parentMethod->getName(),
	))->identifier('method.childParameterType')->build();
}

if (
	in_array($methodName, $this->constructorsHelper->getConstructors($scopeClassReflection), true)
	|| strtolower($methodName) === '__unserialize'
	|| $inClone
) {
	if (TypeUtils::findThisType($scope->getType($propertyFetch->var)) === null) {
		$errors[] = RuleErrorBuilder::message(sprintf('Readonly property %s::$%s is not assigned on $this.', $declaringClass->getDisplayName(), $propertyReflection->getName()))
			->line($propertyFetch->name->getStartLine())
			->identifier('property.readOnlyAssignNotOnThis')
			->build();
	} elseif (
		$inClone
		&& !$scope->hasExpressionType(new CloneReinitializationExpr($propertyReflection->getName()))->no()
	) {
		$errors[] = RuleErrorBuilder::message(sprintf('Readonly property %s::$%s is already assigned.', $declaringClass->getDisplayName(), $propertyReflection->getName()))
			->line($propertyFetch->name->getStartLine())
			->identifier('assign.readOnlyProperty')
			->build();
	}

	continue;
}

try {
    $tmpContainer = new MergeExtensionConfigurationContainerBuilder($extension, $resolvingBag);
    $tmpContainer->setResourceTracking($container->isTrackingResources());
    $tmpContainer->addObjectResource($extension);
    if ($extension instanceof ConfigurationExtensionInterface && null !== $configuration = $extension->getConfiguration($config, $tmpContainer)) {
        $tmpContainer->addObjectResource($configuration);
    }

    foreach ($exprLangProviders as $provider) {
        $tmpContainer->addExpressionLanguageProvider($provider);
    }

    $extension->load($config, $tmpContainer);
} catch (\Exception $e) {
    if ($resolvingBag instanceof MergeExtensionConfigurationParameterBag) {
        $container->getParameterBag()->mergeEnvPlaceholders($resolvingBag);
    }

    throw $e;
}

try {
    $insertStmt = $this->getInsertStatement($sessionId, '', 0);
    $insertStmt->execute();
} catch (\PDOException $e) {
    // Catch duplicate key error because other connection created the session already.
    // It would only not be the case when the other connection destroyed the session.
    if (str_starts_with($e->getCode(), '23')) {
        // Retrieve finished session data written by concurrent connection by restarting the loop.
        // We have to start a new transaction as a failed query will mark the current transaction as
        // aborted in PostgreSQL and disallow further queries within it.
        $this->rollback();
        $this->beginTransaction();
        continue;
    }

    throw $e;
}

foreach ($docComments as $tagName => $docComment) {
    if (!$docComment) {
        continue;
    }

    $tokens = new TokenIterator($this->lexer->tokenize($docComment));
    $docNode = $this->phpDocParser->parse($tokens);

    foreach ($docNode->getTagsByName($tagName) as $tag) {
        $tagValue = $tag->value;

        if ('@var' === $tagName && $tagValue instanceof VarTagValueNode) {
            return $this->stringTypeResolver->resolve((string) $tagValue, $typeContext);
        }

        if ('@param' === $tagName && $tagValue instanceof ParamTagValueNode && '$'.$subject->getName() === $tagValue->parameterName) {
            return $this->stringTypeResolver->resolve((string) $tagValue, $typeContext);
        }

        if ('@return' === $tagName && $tagValue instanceof ReturnTagValueNode) {
            return $this->stringTypeResolver->resolve((string) $tagValue, $typeContext);
        }
    }
}

if ($filterListProviderSet !== null && count($activeAuditFilterLists) > 0) {
    $failingListNames = [];
    foreach ($activeAuditFilterLists as $name => $list) {
        if ($list->audit === ListPolicyConfig::AUDIT_FAIL) {
            $failingListNames[$name] = true;
        }
    }

    $filterResult = $filterAuditor->collectFilterLists($packages, $filterListProviderSet, array_keys($activeAuditFilterLists), $policyConfig->ignoreUnreachable->audit);
    $unreachableRepos = array_merge($unreachableRepos, $filterResult['unreachableRepos']);
    foreach ($packages as $package) {
        $matchingEntries = $filterAuditor->getMatchingAuditEntries($package, $filterResult['filter'], $policyConfig);
        foreach ($matchingEntries as $entry) {
            $filteredPackages[$package->getName()][] = $entry;

            if (isset($failingListNames[$entry->listName])) {
                $filteredCount++;
            }
        }
    }
}

foreach ($repositories as $index => $repo) {
    $repoConfig = RepositoryFactory::configFromString($io, $composer->getConfig(), $repo, true);
    $composerJsonRepositoriesConfig = $composer->getConfig()->getRepositories();
    $name = RepositoryFactory::generateRepositoryName($index, $repoConfig, $composerJsonRepositoriesConfig);
    $configSource = new JsonConfigSource(new JsonFile('composer.json'));

    if (
        (isset($repoConfig['packagist']) && $repoConfig === ['packagist' => false])
        || (isset($repoConfig['packagist.org']) && $repoConfig === ['packagist.org' => false])
    ) {
        $configSource->addRepository('packagist.org', false);
    } else {
        $configSource->addRepository($name, $repoConfig, false);
    }
    $flushLockFile = true;

    $composer = $this->createComposerInstance($input, $io, null, $disablePlugins);
}

if (!$input->getOption('no-autoloader')) {
    $optimize = $input->getOption('optimize-autoloader') || $config->get('optimize-autoloader');
    $authoritative = $input->getOption('classmap-authoritative') || $config->get('classmap-authoritative');
    $apcuPrefix = $input->getOption('apcu-autoloader-prefix');
    $apcu = $apcuPrefix !== null || $input->getOption('apcu-autoloader') || $config->get('apcu-autoloader');

    $generator = $composer->getAutoloadGenerator();
    $generator->setClassMapAuthoritative($authoritative);
    $generator->setApcu($apcu, $apcuPrefix);
    $generator->setPlatformRequirementFilter($this->getPlatformRequirementFilter($input));
    $generator->dump(
        $config,
        $localRepo,
        $package,
        $installationManager,
        'composer',
        $optimize,
        null,
        $composer->getLocker()
    );
}

try {
    if (Platform::isWindows()) {
        // use copy to apply permissions from the destination directory
        // as rename uses source permissions and may block other users
        copy($newFilename, $localFilename);
        @unlink($newFilename);
    } else {
        rename($newFilename, $localFilename);
    }

    return true;
} catch (\Exception $e) {
    // see if we can run this operation as an Admin on Windows
    if (!is_writable(dirname($localFilename))
        && $io->isInteractive()
        && $this->isWindowsNonAdminUser()) {
        return $this->tryAsWindowsAdmin($localFilename, $newFilename);
    }

    @unlink($newFilename);
    $action = 'Composer '.($backupTarget !== null ? 'update' : 'rollback');
    throw new FilesystemException($action.' failed: "'.$localFilename.'" could not be written.'.PHP_EOL.$e->getMessage());
}

if (is_int($name)) {
    if (!isset($this->repositories[$name])) {
        $this->repositories[$name] = $repository;
    } else {
        $this->repositories[] = $repository;
    }
    $this->setSourceOfConfigValue($repository, 'repositories.' . array_search($repository, $this->repositories, true), $source);
} else {
    if ($name === 'packagist') { // BC support for default "packagist" named repo
        $this->repositories[$name . '.org'] = $repository;
        $this->setSourceOfConfigValue($repository, 'repositories.' . $name . '.org', $source);
    } else {
        $this->repositories[$name] = $repository;
        $this->setSourceOfConfigValue($repository, 'repositories.' . $name, $source);
    }
}

if ($packageOrReplacer->getName() !== $name && isset($this->skippedLoad[$packageOrReplacer->getName()])) {
    $replacerName = $packageOrReplacer->getName();
    if ($request->getUpdateAllowTransitiveRootDependencies() || (!$this->isRootRequire($request, $name) && !$this->isRootRequire($request, $replacerName))) {
        $this->unlockPackage($request, $repositories, $replacerName);

        if ($this->isRootRequire($request, $replacerName)) {
            $this->markPackageNameForLoading($request, $replacerName, new MatchAllConstraint);
        } else {
            foreach ($this->packages as $loadedPackage) {
                $requires = $loadedPackage->getRequires();
                if (isset($requires[$replacerName])) {
                    $this->markPackageNameForLoading($request, $replacerName, $requires[$replacerName]->getConstraint());
                }
            }
        }
    }
}

foreach ($pool->getPackages() as $package) {
    // Extract package requirements
    foreach ($package->getRequires() as $link) {
        $this->extractRequireConstraintsPerPackage($link->getTarget(), $link->getConstraint());
    }
    // Extract package conflicts
    foreach ($package->getConflicts() as $link) {
        $this->extractConflictConstraintsPerPackage($link->getTarget(), $link->getConstraint());
    }

    // Keep track of alias packages for every package so if either the alias or aliased is kept
    // we keep the others as they are a unit of packages really
    if ($package instanceof AliasPackage) {
        $this->aliasesPerPackage[$package->getAliasOf()->id][] = $package;
    }
}

if (!$package instanceof AliasPackage) {
    foreach ($package->getNames(false) as $name) {
        $this->addedPackagesByNames[$name][] = $package;
    }
} else {
    $workQueue->enqueue($package->getAliasOf());
    $this->addRule(RuleSet::TYPE_PACKAGE, $this->createRequireRule($package, [$package->getAliasOf()], Rule::RULE_PACKAGE_ALIAS, $package));

    // aliases must be installed with their main package, so create a rule the other way around as well
    $this->addRule(RuleSet::TYPE_PACKAGE, $this->createRequireRule($package->getAliasOf(), [$package], Rule::RULE_PACKAGE_INVERSE_ALIAS, $package->getAliasOf()));

    // if alias package has no self.version requires, its requirements do not
    // need to be added as the aliased package processing will take care of it
    if (!$package->hasSelfVersionRequires()) {
        continue;
    }
}

foreach ($request->getRequires() as $packageName => $constraint) {
    if ($platformRequirementFilter->isIgnored($packageName)) {
        continue;
    } elseif ($platformRequirementFilter instanceof IgnoreListPlatformRequirementFilter) {
        $constraint = $platformRequirementFilter->filterConstraint($packageName, $constraint);
    }

    $packages = $this->pool->whatProvides($packageName, $constraint);
    if (\count($packages) > 0) {
        foreach ($packages as $package) {
            $this->addRulesForPackage($package, $platformRequirementFilter);
        }

        $rule = $this->createInstallOneOfRule($packages, Rule::RULE_ROOT_REQUIRE, [
            'packageName' => $packageName,
            'constraint' => $constraint,
        ]);
        $this->addRule(RuleSet::TYPE_REQUEST, $rule);
    }
}

foreach ($pool->getPackages() as $package) {
    if ($abandoned->block && count($this->auditor->filterAbandonedPackages([$package], $ignoreAbandonedForBlocking)) !== 0) {
        foreach ($package->getNames(false) as $packageName) {
            $abandonedRemovedVersions[$packageName][$package->getVersion()] = $package->getPrettyVersion();
        }
        continue;
    }

    $matchingAdvisories = $this->getMatchingAdvisories($package, $advisoryMap);
    if (count($matchingAdvisories) > 0) {
        foreach ($package->getNames(false) as $packageName) {
            $securityRemovedVersions[$packageName][$package->getVersion()] = $matchingAdvisories;
        }

        continue;
    }

    $packages[] = $package;
}

while (true) {
    switch ($this->io->ask('    <info>Discard changes [y,n,v,?]?</info> ', '?')) {
        case 'y':
            $this->discardChanges($path);
            break 2;

        case 'n':
            throw new \RuntimeException('Update aborted');

        case 'v':
            $this->io->writeError($changes);
            break;

        case '?':
        default:
            $this->io->writeError([
                '    y - discard changes and apply the '.($update ? 'update' : 'uninstall'),
                '    n - abort the '.($update ? 'update' : 'uninstall').' and let you manually clean things up',
                '    v - view modified files',
                '    ? - print help',
            ]);
            break;
    }
}

foreach ($package->getNames(false) as $packageName) {
    if (!isset($filterListMap[$packageName])) {
        continue;
    }

    $packageEntries = array_intersect_key($filterListMap[$packageName], $activeListConfigs);
    if (Preg::isMatch($allIgnoredPackageNamesRegex, $packageName)) {
        $unfilteredEntries = [];
        foreach ($packageEntries as $listName => $entries) {
            if ($this->isPackageIgnored($packageName, $packageConstraint, $activeListConfigs[$listName], $operation)) {
                continue;
            }

            $unfilteredEntries[$listName] = $entries;
        }

        $packageEntries = $unfilteredEntries;
    }

    foreach ($packageEntries as $entries) {
        foreach ($entries as $entry) {
            if ($entry->constraint->matches($packageConstraint)) {
                $matchingEntries[] = $entry;
            }
        }
    }
}

protected function installFullBinaries(string $binPath, string $link, string $bin, PackageInterface $package): void
    {
        // add unixy support for cygwin and similar environments
        if ('.bat' !== substr($binPath, -4)) {
            $this->installUnixyProxyBinaries($binPath, $link);
            $link .= '.bat';
            if (file_exists($link)) {
                $this->io->writeError('    Skipped installation of bin '.$bin.'.bat proxy for package '.$package->getName().': a .bat proxy was already installed');
            }
        }
        if (!file_exists($link)) {
            file_put_contents($link, $this->generateWindowsProxyCode($binPath, $link));
            Silencer::call('chmod', $link, 0777 & ~umask());
        }
    }

    protected function installUnixyProxyBinaries(string $binPath, string $link): void
    {
        file_put_contents($link, $this->generateUnixyProxyCode($binPath, $link));
        Silencer::call('chmod', $link, 0777 & ~umask());
    }

foreach ($tempCollectorErrors as $tempCollectorError) {
	$file = $tempCollectorError->getTraitFilePath() ?? $tempCollectorError->getFilePath();
	$linesToIgnore = $allLinesToIgnore[$file] ?? [];
	$unmatchedLineIgnores = $allUnmatchedLineIgnores[$file] ?? [];
	$localIgnoresProcessorResult = $this->localIgnoresProcessor->process(
		[$tempCollectorError],
		$linesToIgnore,
		$unmatchedLineIgnores,
	);
	foreach ($localIgnoresProcessorResult->getFileErrors() as $error) {
		$errors[] = $error;
		$collectorErrors[] = $error;
	}
	foreach ($localIgnoresProcessorResult->getLocallyIgnoredErrors() as $locallyIgnoredError) {
		$locallyIgnoredErrors[] = $locallyIgnoredError;
		$locallyIgnoredCollectorErrors[] = $locallyIgnoredError;
	}
	$allLinesToIgnore[$file] = $localIgnoresProcessorResult->getLinesToIgnore();
	$allUnmatchedLineIgnores[$file] = $localIgnoresProcessorResult->getUnmatchedLineIgnores();
}

foreach ($clonePropertiesArgTypeConstantArrays as $clonePropertiesArgTypeConstantArray) {
	foreach ($clonePropertiesArgTypeConstantArray->getKeyTypes() as $i => $clonePropertyKeyType) {
		$clonePropertyKeyTypeScalars = $clonePropertyKeyType->getConstantScalarValues();
		$propertyAttributes = $normalizedExpr->getAttributes();
		$propertyAttributes['inCloneWith'] = true;
		if (count($clonePropertyKeyTypeScalars) === 1) {
			$nodeScopeResolver->processVirtualAssign(
				$scope,
				$storage,
				$stmt,
				new PropertyFetch($cloneExpr, (string) $clonePropertyKeyTypeScalars[0], $propertyAttributes),
				new TypeExpr($clonePropertiesArgTypeConstantArray->getValueTypes()[$i]),
				$nodeCallback,
			);
			continue;
		}

		$nodeScopeResolver->processVirtualAssign(
			$scope,
			$storage,
			$stmt,
			new PropertyFetch($cloneExpr, new TypeExpr($clonePropertyKeyType), $propertyAttributes),
			new TypeExpr($clonePropertiesArgTypeConstantArray->getValueTypes()[$i]),
			$nodeCallback,
		);
	}
}

foreach ($clonePropertiesArgTypeConstantArray->getKeyTypes() as $i => $clonePropertyKeyType) {
	$clonePropertyKeyTypeScalars = $clonePropertyKeyType->getConstantScalarValues();
	$propertyAttributes = $normalizedExpr->getAttributes();
	$propertyAttributes['inCloneWith'] = true;
	if (count($clonePropertyKeyTypeScalars) === 1) {
		$nodeScopeResolver->processVirtualAssign(
			$scope,
			$storage,
			$stmt,
			new PropertyFetch($cloneExpr, (string) $clonePropertyKeyTypeScalars[0], $propertyAttributes),
			new TypeExpr($clonePropertiesArgTypeConstantArray->getValueTypes()[$i]),
			$nodeCallback,
		);
		continue;
	}

	$nodeScopeResolver->processVirtualAssign(
		$scope,
		$storage,
		$stmt,
		new PropertyFetch($cloneExpr, new TypeExpr($clonePropertyKeyType), $propertyAttributes),
		new TypeExpr($clonePropertiesArgTypeConstantArray->getValueTypes()[$i]),
		$nodeCallback,
	);
}

if (!$conditionType->isTrue()->no()) {
	$exitPoints = $branchScopeStatementResult->getExitPoints();
	$throwPoints = array_merge($throwPoints, $branchScopeStatementResult->getThrowPoints());
	$impurePoints = array_merge($impurePoints, $branchScopeStatementResult->getImpurePoints());
	$branchScope = $branchScopeStatementResult->getScope();
	$finalScope = $branchScopeStatementResult->isAlwaysTerminating() ? null : $branchScope;
	$alwaysTerminating = $branchScopeStatementResult->isAlwaysTerminating();
	if (count($branchScopeStatementResult->getEndStatements()) > 0) {
		$endStatements = array_merge($endStatements, $branchScopeStatementResult->getEndStatements());
	} elseif (count($stmt->stmts) > 0) {
		$endStatements[] = new InternalEndStatementResult($stmt->stmts[count($stmt->stmts) - 1], $branchScopeStatementResult);
	} else {
		$endStatements[] = new InternalEndStatementResult($stmt, $branchScopeStatementResult);
	}
	$hasYield = $branchScopeStatementResult->hasYield() || $hasYield;
}

if (!$argType->isObject()->no()) {
	$nakedReturnType = null;
	if ($nakedMethodReflection !== null) {
		$nakedParametersAcceptor = ParametersAcceptorSelector::selectFromArgs(
			$scope,
			$args,
			$nakedMethodReflection->getVariants(),
			$nakedMethodReflection->getNamedArgumentsVariants(),
		);
		$nakedReturnType = $nakedParametersAcceptor->getReturnType();
	}
	if (
		$nakedReturnType === null
		|| !(new ThisType($nakedMethodReflection->getDeclaringClass()))->isSuperTypeOf($nakedReturnType)->yes()
		|| $nakedMethodReflection->isPure()->no()
	) {
		$this->callNodeCallback($nodeCallback, new InvalidateExprNode($arg->value), $scope, $storage);
		$scope = $scope->invalidateExpression($arg->value, true);
	}
} elseif (!(new ResourceType())->isSuperTypeOf($argType)->no()) {
	$this->callNodeCallback($nodeCallback, new InvalidateExprNode($arg->value), $scope, $storage);
	$scope = $scope->invalidateExpression($arg->value, true);
}

if ($asserts->getAll() !== []) {
	$parametersAcceptor = ParametersAcceptorSelector::selectFromArgs($scope, $expr->getArgs(), $methodReflection->getVariants(), $methodReflection->getNamedArgumentsVariants());

	$asserts = $asserts->mapTypes(static fn (Type $type) => TemplateTypeHelper::resolveTemplateTypes(
		$type,
		$parametersAcceptor->getResolvedTemplateTypeMap(),
